    static func get(_ key: String, lang: String) -> String {
        let selectedLang: String
        if lang == "system" {
            let systemLang = Locale.preferredLanguages.first?.prefix(2).lowercased() ?? "en"
            selectedLang = translations.keys.contains(systemLang) ? systemLang : "en"
        } else {
            selectedLang = lang
        }
        
        return translations[selectedLang]?[key] ?? translations["en"]?[key] ?? key
    }
